USE jiazheng_miniapp_new;

-- 先清理已有的需求数据（可选）
-- TRUNCATE TABLE demands;

-- 插入需求数据
-- 用户1发布的15条需求

-- 用户2发布的15条需求

-- 统计信息
SELECT '需求数据插入完成！' AS message;
SELECT COUNT(*) AS total_demands FROM demands;
SELECT 
    CASE status 
        WHEN 1 THEN '招募中'
        WHEN 2 THEN '已接单'
        WHEN 3 THEN '进行中'
        WHEN 4 THEN '已完成'
        WHEN 5 THEN '已取消'
        ELSE '未知'
    END AS status_name,
    COUNT(*) AS count
FROM demands 
GROUP BY status;
